pub fn has_encrypted_output(input: &Bytes) -> bool {
    let data = input.as_ref();
    if data.len() < 5 * 32 {
        return false;
    }
    let offset = match read_abi_offset(data, 4) {
        Ok(o) => o,
        Err(_) => return false,
    };
    let bytes = match read_abi_bytes(data, offset) {
        Ok(b) => b,
        Err(_) => return false,
    };
    !bytes.is_empty()
}

pub fn read_abi_bool(data: &[u8], word_index: usize) -> Result<bool, String>
pub fn read_abi_u256(data: &[u8], word_index: usize) -> Result<U256, String>
pub fn read_abi_word<'a>(data: &'a [u8], word_index: usize) -> Result<&'a [u8], String>
pub(crate) fn read_abi_offset(data: &[u8], word_index: usize) -> Result<usize, String>
pub(crate) fn read_abi_bytes<'a>(data: &'a [u8], offset: usize) -> Result<&'a [u8], String>
pub fn read_abi_string(data: &[u8], offset: usize) -> Result<String, String>

pub fn extract_model_from_llm_input(input: &Bytes) -> Result<String, String> {
    let data = input.as_ref();
    if data.len() < 7 * 32 + 32 {
        return Err("LLM input too short to extract model".into());
    }
    let model_offset =
        read_abi_offset(data, 6).map_err(|e| format!("Failed to read model offset: {}", e))?;
    let model = read_abi_string(data, model_offset)
        .map_err(|e| format!("Failed to read model string: {}", e))?;
    if model.trim().is_empty() {
        return Err("Model name is empty".into());
    }
    Ok(model)
}

